using System;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System.Collections.Generic;
using System.Text;
using System.Linq;
using System.Text.RegularExpressions;

public static class ReportingFunction
{
    private static readonly string ConnectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
    
    private static readonly HashSet<string> AllowedColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Id", "Name", "Email", "Department", "Status", "CreatedDate", "ModifiedDate", 
        "Amount", "Category", "Region", "Country", "City", "ProductName", "Quantity"
    };
    
    private static readonly HashSet<string> AllowedTables = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Customers", "Orders", "Products", "Employees", "Sales", "Reports"
    };
    
    private static readonly HashSet<string> AllowedOperators = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "=", "!=", ">", "<", ">=", "<=", "LIKE", "IN"
    };

    [FunctionName("QueryReport")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = "report")] HttpRequest req,
        ILogger log)
    {
        try
        {
            string tableName = req.Query["table"];
            if (string.IsNullOrWhiteSpace(tableName))
            {
                return new BadRequestObjectResult("Table parameter is required");
            }

            if (!IsValidTableName(tableName))
            {
                log.LogWarning($"Invalid table name attempted: {tableName}");
                return new BadRequestObjectResult("Invalid table name");
            }

            var selectColumns = ParseSelectColumns(req.Query["select"]);
            if (selectColumns == null || selectColumns.Count == 0)
            {
                return new BadRequestObjectResult("Invalid or missing select columns");
            }

            var filters = ParseFilters(req);
            if (filters == null)
            {
                return new BadRequestObjectResult("Invalid filter parameters");
            }

            var orderBy = ParseOrderBy(req.Query["orderBy"]);
            var limit = ParseLimit(req.Query["limit"]);

            var query = BuildSecureQuery(tableName, selectColumns, filters, orderBy, limit);
            
            log.LogInformation($"Executing query for table: {tableName}");

            var results = await ExecuteQuery(query.Sql, query.Parameters);
            
            return new OkObjectResult(new
            {
                table = tableName,
                count = results.Count,
                data = results
            });
        }
        catch (SqlException ex)
        {
            log.LogError(ex, "SQL error occurred");
            return new StatusCodeResult(500);
        }
        catch (Exception ex)
        {
            log.LogError(ex, "Error processing request");
            return new StatusCodeResult(500);
        }
    }

    private static bool IsValidTableName(string tableName)
    {
        if (string.IsNullOrWhiteSpace(tableName))
            return false;

        if (!AllowedTables.Contains(tableName))
            return false;

        return Regex.IsMatch(tableName, @"^[a-zA-Z_][a-zA-Z0-9_]*$");
    }

    private static bool IsValidColumnName(string columnName)
    {
        if (string.IsNullOrWhiteSpace(columnName))
            return false;

        if (!AllowedColumns.Contains(columnName))
            return false;

        return Regex.IsMatch(columnName, @"^[a-zA-Z_][a-zA-Z0-9_]*$");
    }

    private static bool IsValidOperator(string op)
    {
        return AllowedOperators.Contains(op?.Trim());
    }

    private static List<string> ParseSelectColumns(string selectParam)
    {
        if (string.IsNullOrWhiteSpace(selectParam))
            return new List<string> { "*" };

        var columns = selectParam.Split(',')
            .Select(c => c.Trim())
            .Where(c => !string.IsNullOrWhiteSpace(c))
            .ToList();

        if (columns.Contains("*"))
            return new List<string> { "*" };

        foreach (var column in columns)
        {
            if (!IsValidColumnName(column))
                return null;
        }

        return columns;
    }

    private static List<FilterCondition> ParseFilters(HttpRequest req)
    {
        var filters = new List<FilterCondition>();

        foreach (var param in req.Query)
        {
            if (param.Key == "table" || param.Key == "select" || param.Key == "orderBy" || param.Key == "limit")
                continue;

            var parts = param.Key.Split('_');
            if (parts.Length < 2)
                continue;

            string columnName = parts[0];
            string operatorStr = parts[1].ToUpper();

            if (!IsValidColumnName(columnName))
                return null;

            if (!IsValidOperator(operatorStr))
                return null;

            string value = param.Value.ToString();
            
            if (string.IsNullOrWhiteSpace(value))
                continue;

            if (operatorStr == "IN")
            {
                var values = value.Split(',').Select(v => v.Trim()).ToList();
                if (values.Any(v => !IsValidValue(v)))
                    return null;
                
                filters.Add(new FilterCondition
                {
                    Column = columnName,
                    Operator = operatorStr,
                    Values = values
                });
            }
            else
            {
                if (!IsValidValue(value))
                    return null;

                filters.Add(new FilterCondition
                {
                    Column = columnName,
                    Operator = operatorStr,
                    Value = value
                });
            }
        }

        return filters;
    }

    private static bool IsValidValue(string value)
    {
        if (string.IsNullOrWhiteSpace(value))
            return false;

        if (value.Length > 1000)
            return false;

        var dangerousPatterns = new[]
        {
            "--", "/*", "*/", ";", "xp_", "sp_", "exec", "execute",
            "drop", "delete", "truncate", "alter", "create", "insert", "update"
        };

        foreach (var pattern in dangerousPatterns)
        {
            if (value.IndexOf(pattern, StringComparison.OrdinalIgnoreCase) >= 0)
                return false;
        }

        return true;
    }

    private static string ParseOrderBy(string orderByParam)
    {
        if (string.IsNullOrWhiteSpace(orderByParam))
            return null;

        var parts = orderByParam.Trim().Split(' ');
        string column = parts[0];

        if (!IsValidColumnName(column))
            return null;

        string direction = "ASC";
        if (parts.Length > 1)
        {
            direction = parts[1].ToUpper();
            if (direction != "ASC" && direction != "DESC")
                return null;
        }

        return $"[{column}] {direction}";
    }

    private static int ParseLimit(string limitParam)
    {
        if (string.IsNullOrWhiteSpace(limitParam))
            return 1000;

        if (int.TryParse(limitParam, out int limit))
        {
            if (limit > 0 && limit <= 10000)
                return limit;
        }

        return 1000;
    }

    private static (string Sql, List<SqlParameter> Parameters) BuildSecureQuery(
        string tableName, 
        List<string> selectColumns, 
        List<FilterCondition> filters, 
        string orderBy, 
        int limit)
    {
        var sql = new StringBuilder();
        var parameters = new List<SqlParameter>();

        string columns = selectColumns.Contains("*") 
            ? "*" 
            : string.Join(", ", selectColumns.Select(c => $"[{c}]"));

        sql.Append($"SELECT TOP (@Limit) {columns} FROM [{tableName}]");
        parameters.Add(new SqlParameter("@Limit", limit));

        if (filters.Count > 0)
        {
            sql.Append(" WHERE ");
            var conditions = new List<string>();

            for (int i = 0; i < filters.Count; i++)
            {
                var filter = filters[i];
                string paramName = $"@Param{i}";

                if (filter.Operator == "IN")
                {
                    var inParams = new List<string>();
                    for (int j = 0; j < filter.Values.Count; j++)
                    {
                        string inParamName = $"{paramName}_{j}";
                        inParams.Add(inParamName);
                        parameters.Add(new SqlParameter(inParamName, filter.Values[j]));
                    }
                    conditions.Add($"[{filter.Column}] IN ({string.Join(", ", inParams)})");
                }
                else if (filter.Operator == "LIKE")
                {
                    conditions.Add($"[{filter.Column}] LIKE {paramName}");
                    parameters.Add(new SqlParameter(paramName, $"%{filter.Value}%"));
                }
                else
                {
                    conditions.Add($"[{filter.Column}] {filter.Operator} {paramName}");
                    parameters.Add(new SqlParameter(paramName, filter.Value));
                }
            }

            sql.Append(string.Join(" AND ", conditions));
        }

        if (!string.IsNullOrWhiteSpace(orderBy))
        {
            sql.Append($" ORDER BY {orderBy}");
        }

        return (sql.ToString(), parameters);
    }

    private static async Task<List<Dictionary<string, object>>> ExecuteQuery(
        string sql, 
        List<SqlParameter> parameters)
    {
        var results = new List<Dictionary<string, object>>();

        using (var connection = new SqlConnection(ConnectionString))
        {
            await connection.OpenAsync();

            using (var command = new SqlCommand(sql, connection))
            {
                command.CommandTimeout = 30;
                
                foreach (var param in parameters)
                {
                    command.Parameters.Add(param);
                }

                using (var reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            string columnName = reader.GetName(i);
                            object value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            row[columnName] = value;
                        }
                        results.Add(row);
                    }
                }
            }
        }

        return results;
    }

    private class FilterCondition
    {
        public string Column { get; set; }
        public string Operator { get; set; }
        public string Value { get; set; }
        public List<string> Values { get; set; }
    }
